={{ (() => {
  const opp    = $('Sanitizar Oportunidad').first().json;
  const scd    = $('Logica SCD2 Oportunidades').first().json;
  const prevRow = $input.first().json;
  const prevChangedAt = prevRow && prevRow.changed_at ? new Date(prevRow.changed_at).getTime() : null;
  const changedAt = opp._changed_at ? new Date(opp._changed_at).getTime() : Date.now();
  const timeInPrev = prevChangedAt ? Math.floor((changedAt - prevChangedAt) / 1000) : null;
  return [
    opp.opportunity_id,
    opp.contact_id,
    opp.location_id,
    scd.prev_stage_id || opp._prev_stage_id,
    scd.prev_stage_name || opp._prev_stage_name,
    opp.pipeline_stage_id,
    opp.stage_name,
    opp.pipeline_id,
    opp.pipeline_name,
    opp.monetary_value,
    opp.status,
    opp.assigned_to_user_id,
    timeInPrev,
    opp._changed_at || new Date().toISOString(),
    'webhook'
  ];
})() }}
